#include <bits/stdc++.h>
using namespace std;

const int N=1e4+100,M=1e6+10;

struct Edge{
    int u,v,w;
}edge[M],ch[N*13];

inline bool cmp(Edge x,Edge y){
    return x.w<y.w;
}

int n,m,k,c[13],a[13][N],f[N],tot;
long long res;

int father(int x){
    return f[x]<0?x:f[x]=father(f[x]);
}

long long solve(int S){
    long long sum=0;
    for(int i=1;i<=k;i++)
        if((S>>i-1)&1)
            sum+=c[i];
    for(int i=1;i<=n+k;i++)
        f[i]=-1;
    for(int i=1;i<=tot;i++){
        if(ch[i].u>n && !((S>>ch[i].u-n-1)&1))
            continue;
        int fu=father(ch[i].u),fv=father(ch[i].v);
        if(fu!=fv){
            if(f[fu]>f[fv])
                swap(fu,fv);
            sum+=ch[i].w;
            f[fu]+=f[fv],f[fv]=fu;
        }
    }
    return sum;
}

int main(){
    scanf("%d%d%d",&n,&m,&k);
    for(int i=1;i<=m;i++)
        scanf("%d%d%d",&edge[i].u,&edge[i].v,&edge[i].w);
    for(int i=1;i<=k;i++){
        scanf("%d",&c[i]);
        for(int j=1;j<=n;j++)
            scanf("%d",&a[i][j]);
    }

    sort(edge+1,edge+m+1,cmp);
    for(int i=1;i<=n;i++)
        f[i]=-1;
    for(int i=1;i<=m;i++){
        int fu=father(edge[i].u),fv=father(edge[i].v);
        if(fu!=fv){
            if(f[fu]>f[fv])
                swap(fu,fv);
            f[fu]+=f[fv],f[fv]=fu;
            res+=edge[i].w;
            ch[++tot]=edge[i];
        }
    }
    for(int i=1;i<=k;i++)
        for(int j=1;j<=n;j++)
            ch[++tot]={n+i,j,a[i][j]};
    sort(ch+1,ch+tot+1,cmp);

    for(int i=1;i<1<<k;i++)
        res=min(res,solve(i));
    printf("%lld",res);
    return 0;
}
